+    assert!(
+        batch.records.iter().all(|record| record.epoch == 0),
+        "records appended during the fence window must stay in epoch 0: {:?}",
+        batch
+            .records
+            .iter()
+            .map(|record| record.epoch)
+            .collect::<Vec<_>>()
+    );
